#### `board.py`
Manages the board state and game logic.

```python
class Piece:
    def __init__(self, owner):
        self.owner = owner  # 'r' for red, 'b' for black
        self.king = False

    def make_king(self):
        self.king = True

    def __str__(self):
        return 'R' if self.owner == 'r' else 'B'

class Board:
    def __init__(self):
        self.grid = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        pieces = ['b', 'r']
        for piece in pieces:
            for i in range(3):
                for j in range(i % 2, 8, 2):
                    if piece == 'b':
                        self.grid[i][j] = Piece(piece)
                    else:
                        self.grid[7 - i][7 - j] = Piece(piece)

    def print_board(self):
        for row in self.grid:
            print(' '.join(str(cell) if cell else '.' for cell in row))

# Example usage
if __name__ == "__main__":
    board = Board()
    board.print_board()
```

